const e=JSON.parse('{"key":"v-51bc2637","path":"/%E6%95%B0%E6%8D%AE%E5%BA%93/Redis/%E5%8E%9F%E7%90%86%E7%AF%87/03-RESP%E5%8D%8F%E8%AE%AE.html","title":"RESP协议","lang":"zh-CN","frontmatter":{"date":"2021-09-10T00:00:00.000Z","category":["Redis"],"tag":["Redis"],"order":3,"description":"RESP协议 Redis是一个CS架构的软件，通信一般分两步（不包括pipeline和PubSub）： 客户端（client）向服务端（server）发送一条命令 服务端解析并执行命令，返回响应结果给客户端 因此客户端发送命令的格式、服务端响应结果的格式必须有一个规范，这个规范就是通信协议。 而在Redis中采用的是RESP（Redis Serialization Protocol）协议： Redis 1.2版本引入了RESP协议 Redis 2.0版本中成为与Redis服务端通信的标准，称为RESP2 Redis 6.0版本中，从RESP2升级到了RESP3协议，增加了更多数据类型并且支持6.0的新特性--客户端缓存","head":[["meta",{"property":"og:url","content":"https://mister-hope.github.io/%E6%95%B0%E6%8D%AE%E5%BA%93/Redis/%E5%8E%9F%E7%90%86%E7%AF%87/03-RESP%E5%8D%8F%E8%AE%AE.html"}],["meta",{"property":"og:site_name","content":"Journey of Growth"}],["meta",{"property":"og:title","content":"RESP协议"}],["meta",{"property":"og:description","content":"RESP协议 Redis是一个CS架构的软件，通信一般分两步（不包括pipeline和PubSub）： 客户端（client）向服务端（server）发送一条命令 服务端解析并执行命令，返回响应结果给客户端 因此客户端发送命令的格式、服务端响应结果的格式必须有一个规范，这个规范就是通信协议。 而在Redis中采用的是RESP（Redis Serialization Protocol）协议： Redis 1.2版本引入了RESP协议 Redis 2.0版本中成为与Redis服务端通信的标准，称为RESP2 Redis 6.0版本中，从RESP2升级到了RESP3协议，增加了更多数据类型并且支持6.0的新特性--客户端缓存"}],["meta",{"property":"og:type","content":"article"}],["meta",{"property":"og:locale","content":"zh-CN"}],["meta",{"property":"og:updated_time","content":"2023-11-22T16:29:49.000Z"}],["meta",{"property":"article:author","content":"Mr.G"}],["meta",{"property":"article:tag","content":"Redis"}],["meta",{"property":"article:published_time","content":"2021-09-10T00:00:00.000Z"}],["meta",{"property":"article:modified_time","content":"2023-11-22T16:29:49.000Z"}],["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@type\\":\\"Article\\",\\"headline\\":\\"RESP协议\\",\\"image\\":[\\"\\"],\\"datePublished\\":\\"2021-09-10T00:00:00.000Z\\",\\"dateModified\\":\\"2023-11-22T16:29:49.000Z\\",\\"author\\":[{\\"@type\\":\\"Person\\",\\"name\\":\\"Mr.G\\",\\"url\\":\\"https://mister-hope.com\\"}]}"]]},"headers":[{"level":2,"title":"1、基于Socket自定义Redis的客户端","slug":"_1、基于socket自定义redis的客户端","link":"#_1、基于socket自定义redis的客户端","children":[]},{"level":2,"title":"2、Redis内存回收-过期key处理","slug":"_2、redis内存回收-过期key处理","link":"#_2、redis内存回收-过期key处理","children":[{"level":3,"title":"2.1、内存过期策略","slug":"_2-1、内存过期策略","link":"#_2-1、内存过期策略","children":[]},{"level":3,"title":"2.2、内存淘汰策略","slug":"_2-2、内存淘汰策略","link":"#_2-2、内存淘汰策略","children":[]}]}],"git":{"createdTime":1700417401000,"updatedTime":1700670589000,"contributors":[{"name":"gm-hacker","email":"gm-hacker@qq.com","commits":3}]},"readingTime":{"minutes":9.56,"words":2869},"filePathRelative":"数据库/Redis/原理篇/03-RESP协议.md","localizedDate":"2021年9月10日","excerpt":"<h1> RESP协议</h1>\\n<p>Redis是一个CS架构的软件，通信一般分两步（不包括pipeline和PubSub）：</p>\\n<ol>\\n<li>\\n<p>客户端（client）向服务端（server）发送一条命令</p>\\n</li>\\n<li>\\n<p>服务端解析并执行命令，返回响应结果给客户端</p>\\n</li>\\n</ol>\\n<p>因此客户端发送命令的格式、服务端响应结果的格式必须有一个规范，这个规范就是通信协议。</p>\\n<p>而在Redis中采用的是<strong>RESP</strong>（Redis Serialization Protocol）协议：</p>\\n<ul>\\n<li>\\n<p>Redis 1.2版本引入了RESP协议</p>\\n</li>\\n<li>\\n<p>Redis 2.0版本中成为与Redis服务端通信的标准，称为RESP2</p>\\n</li>\\n<li>\\n<p>Redis 6.0版本中，从RESP2升级到了RESP3协议，增加了更多数据类型并且支持6.0的新特性--客户端缓存</p>\\n</li>\\n</ul>","autoDesc":true}');export{e as data};
